import { BUILT_IN_THEMES, DEFAULT_THEME_ID, type ThemeId, type BuiltInTheme } from "@t3tools/shared/theme";
import { useCallback, useEffect, useSyncExternalStore } from "react";

const STORAGE_KEY = "t3code:theme";
// ... module-level state, listeners, etc. (same pattern as before)

function getStoredThemeId(): ThemeId { /* read + validate + migrate legacy values */ }

function buildCssVars(theme: BuiltInTheme): Record<string, string> {
  const c = theme.colors;
  return {
    "--background": c.background,
    "--foreground": c.foreground,
    "--card": c.card,
    "--card-foreground": c.cardForeground,
    "--popover": c.popover,
    "--popover-foreground": c.popoverForeground,
    "--primary": c.accent,           // ThemeColorDefinition.accent → CSS --primary
    "--primary-foreground": c.accentForeground,
    "--secondary": c.secondary,
    "--secondary-foreground": c.secondaryForeground,
    "--muted": c.muted,
    "--muted-foreground": c.mutedForeground,
    "--accent": c.secondary,         // CSS --accent (hover surface) = secondary color
    "--accent-foreground": c.secondaryForeground,
    "--destructive": c.destructive,
    "--destructive-foreground": c.destructiveForeground,
    "--border": c.border,
    "--input": c.input,
    "--ring": c.ring,
    // New area variables (available for UI components to adopt)
    "--sidebar": c.sidebar,
    "--sidebar-foreground": c.sidebarForeground,
    "--editor": c.editor,
    "--editor-foreground": c.editorForeground,
    "--terminal": c.terminal,
    "--terminal-foreground": c.terminalForeground,
    "--status-bar": c.statusBar,
    "--status-bar-foreground": c.statusBarForeground,
  };
}

function applyTheme(themeId: ThemeId, suppressTransitions = false) {
  const theme = BUILT_IN_THEMES[themeId];
  const isDark = theme.colorScheme === "dark";
  if (suppressTransitions) document.documentElement.classList.add("no-transitions");
  for (const [key, value] of Object.entries(buildCssVars(theme))) {
    document.documentElement.style.setProperty(key, value);
  }
  document.documentElement.style.setProperty("color-scheme", isDark ? "dark" : "light");
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    document.documentElement.offsetHeight; // force reflow
    requestAnimationFrame(() => document.documentElement.classList.remove("no-transitions"));
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStoredThemeId());

export function useTheme() {
  // useSyncExternalStore + storage/mediaQuery listeners (same pattern as existing)
  // Returns:
  return {
    themeId,           // ThemeId — the stored selection
    theme,             // BuiltInTheme — full theme object
    setTheme,          // (id: ThemeId) => void
    resolvedTheme,     // "light" | "dark" — theme.colorScheme, for diff renderer compat
  } as const;
}
```

