---

### Step 2 — `packages/shared/package.json` (MODIFY)

Add a new entry to the `"exports"` object, following the exact same pattern as all other subpath exports:

```json
"./theme": {
  "types": "./src/theme.ts",
  "import": "./src/theme.ts"
}
```

No other changes. No new dependencies needed.

---

### Step 3 — `apps/web/src/hooks/useTheme.ts` (REPLACE)

Full replacement of the existing file. Key design decisions:
- Storage key stays `"t3code:theme"` — existing values `"light"`, `"dark"`, `"system"` are migrated gracefully to `"t3-light"`, `"t3-dark"`, `"t3-dark"` respectively.
- Module-level `applyTheme(getStoredThemeId())` runs immediately on import to prevent render flash.
- CSS variables are applied via `document.documentElement.style.setProperty()` (inline styles override the `:root` stylesheet rules; the `@variant dark` block in `index.css` becomes a pure fallback).
- `.dark` CSS class is still toggled for Tailwind `dark:` utilities used throughout the app.
- `color-scheme` CSS property is set inline as well.

```typescript
import { BUILT_IN_THEMES, DEFAULT_THEME_ID, type ThemeId, type BuiltInTheme } from "@t3tools/shared/theme";
import { useCallback, useEffect, useSyncExternalStore } from "react";

const STORAGE_KEY = "t3code:theme";
// ... module-level state, listeners, etc. (same pattern as before)

function getStoredThemeId(): ThemeId { /* read + validate + migrate legacy values */ }

function buildCssVars(theme: BuiltInTheme): Record<string, string> {
  const c = theme.colors;
  return {
    "--background": c.background,
    "--foreground": c.foreground,
    "--card": c.card,
    "--card-foreground": c.cardForeground,
    "--popover": c.popover,
    "--popover-foreground": c.popoverForeground,
    "--primary": c.accent,           // ThemeColorDefinition.accent → CSS --primary
    "--primary-foreground": c.accentForeground,
    "--secondary": c.secondary,
    "--secondary-foreground": c.secondaryForeground,
    "--muted": c.muted,
    "--muted-foreground": c.mutedForeground,
    "--accent": c.secondary,         // CSS --accent (hover surface) = secondary color
    "--accent-foreground": c.secondaryForeground,
    "--destructive": c.destructive,
    "--destructive-foreground": c.destructiveForeground,
    "--border": c.border,
    "--input": c.input,
    "--ring": c.ring,
    // New area variables (available for UI components to adopt)
    "--sidebar": c.sidebar,
    "--sidebar-foreground": c.sidebarForeground,
    "--editor": c.editor,
    "--editor-foreground": c.editorForeground,
    "--terminal": c.terminal,
    "--terminal-foreground": c.terminalForeground,
    "--status-bar": c.statusBar,
    "--status-bar-foreground": c.statusBarForeground,
  };
}

function applyTheme(themeId: ThemeId, suppressTransitions = false) {
  const theme = BUILT_IN_THEMES[themeId];
  const isDark = theme.colorScheme === "dark";
  if (suppressTransitions) document.documentElement.classList.add("no-transitions");
  for (const [key, value] of Object.entries(buildCssVars(theme))) {
    document.documentElement.style.setProperty(key, value);
  }
  document.documentElement.style.setProperty("color-scheme", isDark ? "dark" : "light");
  document.documentElement.classList.toggle("dark", isDark);
  if (suppressTransitions) {
    document.documentElement.offsetHeight; // force reflow
    requestAnimationFrame(() => document.documentElement.classList.remove("no-transitions"));
  }
}

// Apply immediately on module load to prevent flash
applyTheme(getStoredThemeId());

export function useTheme() {
  // useSyncExternalStore + storage/mediaQuery listeners (same pattern as existing)
  // Returns:
  return {
    themeId,           // ThemeId — the stored selection
    theme,             // BuiltInTheme — full theme object
    setTheme,          // (id: ThemeId) => void
    resolvedTheme,     // "light" | "dark" — theme.colorScheme, for diff renderer compat
  } as const;
}
```

**Backward compat**: `resolvedTheme: "light" | "dark"` is preserved — `DiffPanel`, `DiffWorkerPoolProvider`, `ChatMarkdown`, `ChatView` all use only `resolvedTheme` and continue to work unchanged.

Note: the `"system"` preference detection (matchMedia) is removed. Users now pick a specific named theme. The OS dark-mode media query listener is no longer needed.

---

### Step 4 — `apps/web/src/main.tsx` (MODIFY)

Add a side-effect import immediately before `ReactDOM.createRoot().render()` to ensure the module-level `applyTheme(getStoredThemeId())` runs before React renders, preventing a theme flash:

```typescript
import "./hooks/useTheme"; // Apply stored theme immediately to prevent flash
```

Place this after `import "./index.css"` and before the `ReactDOM.createRoot` call.

---

### Step 5 — `apps/web/src/components/ThemeProvider.tsx` (NEW)

Minimal wrapper component that serves as the conceptual boundary for the theme system. It does not need its own Context because the module-level external store handles all state. Its primary job is ensuring the theme is applied when the component tree mounts:

```tsx
import { useEffect } from "react";
import { useTheme } from "../hooks/useTheme";

export function ThemeProvider({ children }: { children: React.ReactNode }) {
  const { themeId } = useTheme();
  // The hook's module-level code applies the theme on load;
  // useEffect here ensures re-application on SSR hydration or hot reload.
  useEffect(() => {
    // applyTheme is called internally by the hook on every themeId change
  }, [themeId]);
  return <>{children}</>;
}
```

---

### Step 6 — `apps/web/src/routes/__root.tsx` (MODIFY)

Import `ThemeProvider` and wrap the root render in `RootRouteView`:

```tsx
