}
```

---

### Step 7 — `apps/web/src/components/ThemeSelector.tsx` (NEW)

Theme selector component with visual preview swatches:

```tsx
import { CheckIcon } from "lucide-react";
import { BUILT_IN_THEMES, BUILT_IN_THEME_IDS } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";

export function ThemeSelector() {
  const { themeId, setTheme } = useTheme();

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Color theme">
      {BUILT_IN_THEME_IDS.map((id) => {
        const builtInTheme = BUILT_IN_THEMES[id];
        const isSelected = themeId === id;
        return (
          <button key={id} type="button" role="radio" aria-checked={isSelected}
            onClick={() => setTheme(id)}
            className={cn(
              "flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors",
