                 style={{ background: builtInTheme.colors.background, border: `1px solid ${builtInTheme.colors.border}` }}>
              {/* Sidebar strip */}
              <div className="absolute inset-y-0 left-0 w-[28%]"
                   style={{ background: builtInTheme.colors.sidebar }} />
              {/* Editor area */}
              <div className="absolute inset-y-0 left-[28%] right-0"
                   style={{ background: builtInTheme.colors.editor }} />
              {/* Accent dot */}
              <div className="absolute bottom-2 right-2 h-3 w-3 rounded-full"
                   style={{ background: builtInTheme.colors.accent }} />
              {/* Status bar */}
              <div className="absolute inset-x-0 bottom-0 h-2"
                   style={{ background: builtInTheme.colors.statusBar }} />
            </div>
            {/* Name + check */}
            <div className="flex items-center justify-between gap-1">
              <span className="text-xs font-medium text-foreground">{builtInTheme.name}</span>
              {isSelected && <CheckIcon className="size-3 text-primary" />}
            </div>
