/** Identifier for a built-in theme. */
export type ThemeId = "t3-light" | "t3-dark" | "t3-midnight";

/**
 * Full color definition for a theme. Covers all areas of the editor UI:
 * background, foreground, accent, sidebar, editor, terminal, status bar,
 * plus supporting tokens required by the CSS variable system.
 *
 * All color values are CSS color strings (oklch(), color-mix(), var(), hex, etc.)
 * and are applied as CSS custom properties on `document.documentElement`.
 */
export interface ThemeColorDefinition {
  // === Required semantic areas ===

  /** Main app background. */
  background: string;
  /** Main text color. */
  foreground: string;
  /** Brand accent / primary action color. Maps to CSS --primary. */
  accent: string;
  /** Text rendered on top of the accent color. */
  accentForeground: string;
  /** Sidebar panel background. */
  sidebar: string;
  /** Sidebar text color. */
  sidebarForeground: string;
  /** Code editor pane background. */
  editor: string;
  /** Code editor text color. */
  editorForeground: string;
  /** Integrated terminal background. */
  terminal: string;
  /** Integrated terminal text color. */
  terminalForeground: string;
  /** Status bar background. */
  statusBar: string;
  /** Status bar text color. */
  statusBarForeground: string;

  // === Supporting tokens (required by the existing CSS variable system) ===

  /** Card / elevated surface background. */
  card: string;
  /** Card text color. */
  cardForeground: string;
  /** Popover / dropdown background. */
  popover: string;
  /** Popover text color. */
  popoverForeground: string;
  /**
   * Subtle interactive surface used for hover backgrounds,
   * secondary buttons, and muted containers.
   * Maps to CSS --secondary, --muted, and --accent (hover surface).
   */
  secondary: string;
  /** Text on secondary surfaces. */
  secondaryForeground: string;
  /** Muted / subdued background. Maps to CSS --muted. */
  muted: string;
  /** Muted / subdued text. */
  mutedForeground: string;
  /** Border / divider color. */
  border: string;
  /** Input field border / background tint. */
  input: string;
  /** Focus ring color. */
  ring: string;
  /** Destructive / error color. */
  destructive: string;
  /** Text on destructive backgrounds. */
  destructiveForeground: string;
}

/** A complete built-in theme with metadata and color definitions. */
export interface BuiltInTheme {
  /** Unique identifier. */
  id: ThemeId;
  /** Display name shown in the UI. */
  name: string;
  /** Whether this theme is light or dark. Drives the `.dark` CSS class and `color-scheme`. */
  colorScheme: "light" | "dark";
  /** Full color token set. */
  colors: ThemeColorDefinition;
}

