import { useCallback, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  type BuiltInTheme,
  type ThemeId,
} from "@t3tools/shared/theme";

const STORAGE_KEY = "t3code:theme";

// ---------------------------------------------------------------------------
// Module-level external store (same pattern as appSettings.ts)
// ---------------------------------------------------------------------------

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeId | null = null;

function emitChange() {
  for (const listener of listeners) listener();
}

/**
 * Read and validate the stored ThemeId. Migrates legacy values from the old
 * "light" | "dark" | "system" system to the nearest named theme.
 */
function getStoredThemeId(): ThemeId {
  if (typeof window === "undefined") return DEFAULT_THEME_ID;

  const raw = localStorage.getItem(STORAGE_KEY);

  // Valid ThemeId — return as-is
  if (raw === "t3-light" || raw === "t3-dark" || raw === "t3-midnight") return raw;

  // Migrate legacy values from the old light/dark/system toggle
  if (raw === "light") return "t3-light";
  if (raw === "dark") return "t3-dark";
  // "system" and anything unrecognised → default
  return DEFAULT_THEME_ID;
}

// ---------------------------------------------------------------------------
// CSS variable application
// ---------------------------------------------------------------------------

/**
 * Build the full CSS custom property map for a theme.
 *
 * The ThemeColorDefinition.accent field represents the brand accent color and
 * maps to the CSS `--primary` variable (the bold action color used by buttons,
 * links, etc.). The CSS `--accent` variable is the subtle hover surface and
 * maps to the `secondary` field (same translucent value used for hover states).
 */
function buildCssVars(theme: BuiltInTheme): Record<string, string> {
  const c = theme.colors;
  return {
    // Core surfaces
    "--background": c.background,
    "--foreground": c.foreground,
    // Cards & popovers
    "--card": c.card,
    "--card-foreground": c.cardForeground,
    "--popover": c.popover,
    "--popover-foreground": c.popoverForeground,
    // Brand accent → CSS --primary
    "--primary": c.accent,
    "--primary-foreground": c.accentForeground,
    // Subtle surfaces (secondary, muted, hover accent)
    "--secondary": c.secondary,
    "--secondary-foreground": c.secondaryForeground,
    "--muted": c.muted,
    "--muted-foreground": c.mutedForeground,
    "--accent": c.secondary, // CSS --accent is the hover surface, same as secondary
    "--accent-foreground": c.secondaryForeground,
    // Destructive
    "--destructive": c.destructive,
    "--destructive-foreground": c.destructiveForeground,
    // Chrome
    "--border": c.border,
    "--input": c.input,
    "--ring": c.ring,
    // Area-specific variables (new — available for components to reference)
    "--sidebar": c.sidebar,
    "--sidebar-foreground": c.sidebarForeground,
    "--editor": c.editor,
    "--editor-foreground": c.editorForeground,
    "--terminal": c.terminal,
    "--terminal-foreground": c.terminalForeground,
    "--status-bar": c.statusBar,
    "--status-bar-foreground": c.statusBarForeground,
  };
}

/**
 * Apply a theme to the document root by setting CSS custom properties as
 * inline styles (highest specificity, overrides the stylesheet fallbacks in
 * index.css) and toggling the `.dark` class for Tailwind `dark:` utilities.
 */
function applyTheme(themeId: ThemeId, suppressTransitions = false) {
  if (typeof window === "undefined") return;

  const theme = BUILT_IN_THEMES[themeId];
  const isDark = theme.colorScheme === "dark";

  if (suppressTransitions) {
    document.documentElement.classList.add("no-transitions");
  }

  // Inject all CSS custom properties as inline styles
  for (const [key, value] of Object.entries(buildCssVars(theme))) {
    document.documentElement.style.setProperty(key, value);
  }

  // Set the standard color-scheme property
  document.documentElement.style.setProperty("color-scheme", isDark ? "dark" : "light");

  // Toggle .dark for Tailwind dark: utilities throughout the app
  document.documentElement.classList.toggle("dark", isDark);

  if (suppressTransitions) {
    // Force a reflow so no-transitions takes effect before removal
    // oxlint-disable-next-line no-unused-expressions
    document.documentElement.offsetHeight;
    requestAnimationFrame(() => {
      document.documentElement.classList.remove("no-transitions");
    });
  }
}

// Apply immediately on module load to prevent flash before React renders
applyTheme(getStoredThemeId());

// ---------------------------------------------------------------------------
// useSyncExternalStore plumbing
// ---------------------------------------------------------------------------

function getSnapshot(): ThemeId {
  const themeId = getStoredThemeId();
  if (lastSnapshot === themeId) return lastSnapshot;
  lastSnapshot = themeId;
  return themeId;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  // Listen for cross-tab storage changes
  const handleStorage = (e: StorageEvent) => {
    if (e.key === STORAGE_KEY) {
      applyTheme(getStoredThemeId(), true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// ---------------------------------------------------------------------------
// Public hook
// ---------------------------------------------------------------------------

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = BUILT_IN_THEMES[themeId];

  /**
   * resolvedTheme is "light" | "dark" derived from the theme's colorScheme.
   * Kept for backward compatibility with DiffPanel, ChatMarkdown, ChatView,
   * and DiffWorkerPoolProvider which pass it to resolveDiffThemeName().
   */
  const resolvedTheme: "light" | "dark" = theme.colorScheme;

  const setTheme = useCallback((nextId: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, nextId);
    applyTheme(nextId, true);
    emitChange();
  }, []);

  return { themeId, theme, setTheme, resolvedTheme } as const;
}

