import { type ReactNode } from "react";
import { useTheme } from "../hooks/useTheme";

interface ThemeProviderProps {
  children: ReactNode;
}

/**
 * ThemeProvider is the semantic boundary for the custom theme system.
 *
 * Theme state is managed by module-level external store in useTheme.ts, so no
 * React Context is required. This component subscribes to the store via
 * useTheme() to ensure the component tree re-renders when the theme changes,
 * and serves as a clear architectural marker for where theming lives.
 *
 * Place this as a top-level wrapper in the root layout.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  // Subscribing here guarantees React re-renders propagate on theme changes
  // even if a subtree doesn't call useTheme() itself.
  useTheme();
  return <>{children}</>;
}

