import { CheckIcon } from "lucide-react";
import { BUILT_IN_THEME_IDS, BUILT_IN_THEMES } from "@t3tools/shared/theme";
import { useTheme } from "../hooks/useTheme";
import { cn } from "../lib/utils";

/**
 * ThemeSelector renders a row of clickable theme cards, each showing a
 * mini preview swatch of the theme's key colors (sidebar, editor, accent,
 * and status bar) plus the theme name and a check mark when selected.
 *
 * Uses inline styles on the swatch elements so colors are always accurate
 * regardless of which theme is currently active.
 */
export function ThemeSelector() {
  const { themeId, setTheme } = useTheme();

  return (
    <div className="grid grid-cols-3 gap-3" role="radiogroup" aria-label="Color theme">
      {BUILT_IN_THEME_IDS.map((id) => {
        const builtInTheme = BUILT_IN_THEMES[id];
        const isSelected = themeId === id;

        return (
          <button
            key={id}
            type="button"
            role="radio"
            aria-checked={isSelected}
            onClick={() => setTheme(id)}
            className={cn(
              "flex flex-col gap-2 rounded-xl border p-3 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring",
              isSelected
                ? "border-primary/60 bg-primary/8"
                : "border-border bg-background hover:bg-accent",
            )}
          >
            {/* Mini layout preview swatch */}
            <div
              className="relative h-14 w-full overflow-hidden rounded-lg"
              style={{
                background: builtInTheme.colors.background,
                boxShadow: `inset 0 0 0 1px ${builtInTheme.colors.border}`,
              }}
              aria-hidden="true"
            >
              {/* Sidebar strip (left ~28%) */}
              <div
                className="absolute inset-y-0 left-0 w-[28%]"
                style={{ background: builtInTheme.colors.sidebar }}
              />
              {/* Editor area (right ~72%) */}
              <div
                className="absolute inset-y-0 left-[28%] right-0"
                style={{ background: builtInTheme.colors.editor }}
              />
              {/* Sidebar/editor divider line */}
              <div
                className="absolute inset-y-0 left-[28%] w-px"
                style={{ background: builtInTheme.colors.border }}
              />
              {/* Simulated editor content lines */}
              <div className="absolute left-[34%] right-4 top-3 flex flex-col gap-1.5">
                <div
                  className="h-1 w-3/4 rounded-full opacity-30"
                  style={{ background: builtInTheme.colors.foreground }}
                />
                <div
                  className="h-1 w-1/2 rounded-full opacity-20"
                  style={{ background: builtInTheme.colors.foreground }}
                />
              </div>
              {/* Accent dot (bottom-right) */}
              <div
                className="absolute bottom-3 right-3 h-3 w-3 rounded-full"
                style={{ background: builtInTheme.colors.accent }}
              />
              {/* Status bar strip (bottom) */}
              <div
                className="absolute inset-x-0 bottom-0 h-2"
                style={{ background: builtInTheme.colors.statusBar }}
              />
            </div>

            {/* Theme name + selected indicator */}
            <div className="flex items-center justify-between gap-1">
              <span className="text-xs font-medium text-foreground">{builtInTheme.name}</span>
              {isSelected ? (
                <CheckIcon className="size-3 shrink-0 text-primary" aria-label="Selected" />
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

